function Tip({text}){const[o,setO]=useState(false);return(<span className="relative inline-block ml-1"><button onClick={()=>setO(!o)} className="w-5 h-5 rounded-full bg-slate-200 text-slate-600 text-xs font-bold inline-flex items-center justify-center">?</button>{o&&<div className="absolute z-50 bottom-7 left-1/2 -translate-x-1/2 w-72 bg-slate-800 text-white text-sm rounded-xl p-3 shadow-xl" style={{maxWidth:"85vw"}}>{text}</div>}</span>);}
function Card({children,className=""}){return<div className={"bg-white rounded-2xl shadow-sm border border-slate-200 p-5 "+className}>{children}</div>;}
function Sel({label,value,onChange,options,tooltip,id}){return(<div className="mb-4"><label htmlFor={id} className="block text-sm font-semibold text-slate-700 mb-1">{label}{tooltip&&<Tip text={tooltip}/>}</label><select id={id} value={value} onChange={e=>onChange(e.target.value)} className="w-full border border-slate-300 rounded-xl px-4 py-3 text-slate-800 bg-white outline-none text-base">{options.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</select></div>);}
function Inp({label,value,onChange,type="number",placeholder,tooltip,suffix,id}){return(<div className="mb-4"><label htmlFor={id} className="block text-sm font-semibold text-slate-700 mb-1">{label}{tooltip&&<Tip text={tooltip}/>}</label><div className="relative"><input id={id} type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} className="w-full border border-slate-300 rounded-xl px-4 py-3 text-slate-800 bg-white outline-none text-base"/>{suffix&&<span className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm">{suffix}</span>}</div></div>);}
function Btn({onClick,children,secondary}){return secondary?<button onClick={onClick} className="border border-slate-300 text-slate-600 font-semibold px-6 py-3 rounded-xl hover:bg-slate-50 text-sm">{children}</button>:<button onClick={onClick} className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-semibold px-6 py-3 rounded-xl shadow text-sm">{children}</button>;}
function Prog({c,t}){const p=t>0?Math.round(c/t*100):0;return(<div className="w-full mb-6"><div className="flex justify-between text-sm text-slate-500 mb-1"><span>Étape {c}/{t}</span><span>{p}%</span></div><div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden"><div className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full transition-all duration-500" style={{width:`${p}%`}}/></div></div>);}
function BCards({items}){return(<div className="grid gap-2 mt-2">{items.map((b,i)=>(<div key={i} className="border-2 rounded-xl p-3 border-slate-200 bg-slate-50"><div className="flex items-center gap-2"><span className="text-xl">{b.e}</span><span className="font-bold text-slate-800 text-sm">{b.n}</span>{i===0&&<span className="text-xs bg-yellow-400 text-yellow-900 px-2 py-0.5 rounded-full font-bold ml-auto">Top</span>}</div>{b.f&&<p className="text-xs text-slate-600 mt-1">{b.f}</p>}</div>))}</div>);}
function DCard({children,style={},className=""}){return<div className={className} style={{background:DK.card,border:`1px solid ${DK.bd}`,borderRadius:16,padding:18,...style}}>{children}</div>;}
function DInp({label,value,onChange,type="number",placeholder,suffix,id}){return(<div className="mb-3"><label htmlFor={id} className="block text-xs font-semibold mb-1" style={{color:DK.sub}}>{label}</label><div className="relative"><input id={id} type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={{background:DK.card2,border:`1px solid ${DK.bd}`,color:DK.txt}} className="w-full rounded-xl px-3 py-2.5 outline-none text-sm"/>{suffix&&<span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs" style={{color:DK.sub}}>{suffix}</span>}</div></div>);}
function DSel({label,value,onChange,options,id}){return(<div className="mb-3"><label htmlFor={id} className="block text-xs font-semibold mb-1" style={{color:DK.sub}}>{label}</label><select id={id} value={value} onChange={e=>onChange(e.target.value)} style={{background:DK.card2,border:`1px solid ${DK.bd}`,color:DK.txt}} className="w-full rounded-xl px-3 py-2.5 outline-none text-sm">{options.map(o=><option key={o.value} value={o.value} style={{background:DK.card2}}>{o.label}</option>)}</select></div>);}
function Gauge({score,size=90}){const color=score>=70?DK.grn:score>=40?"#f59e0b":DK.red;const r=size/2-5;const circ=2*Math.PI*r;return(<div className="relative" style={{width:size,height:size}}><svg viewBox={`0 0 ${size} ${size}`} className="-rotate-90"><circle cx={size/2} cy={size/2} r={r} fill="none" stroke={DK.bd} strokeWidth="7"/><circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth="7" strokeDasharray={circ} strokeDashoffset={circ*(1-score/100)} strokeLinecap="round"/></svg><span className="absolute inset-0 flex items-center justify-center font-bold text-lg" style={{color:DK.txt}}>{score}</span></div>);}

