const[loyer,setLoyer]=useState(I("loyer",""));const[alimentation,setAlimentation]=useState(I("alimentation",""));const[transports,setTransports]=useState(I("transports",""));const[abonnements,setAbonnements]=useState(I("abonnements",""));const[assurancesCh,setAssurancesCh]=useState(I("assurancesCh",""));const[loisirs,setLoisirs]=useState(I("loisirs",""));const[creditsConso,setCreditsConso]=useState(I("creditsConso",""));const[autresCharges,setAutresCharges]=useState(I("autresCharges",""));
const[epargnePrecaution,setEpargnePrecaution]=useState(I("epargnePrecaution",""));const[montantEpargne,setMontantEpargne]=useState(I("montantEpargne",""));const[aLivretA,setALivretA]=useState(I("aLivretA",""));const[aLDDS,setALDDS]=useState(I("aLDDS",""));
const[aPEA,setAPEA]=useState(I("aPEA",""));const[aPER,setAPER]=useState(I("aPER",""));const[aAV,setAAV]=useState(I("aAV",""));
const[peaMontant,setPeaMontant]=useState(I("peaMontant",""));const[peaDepuis,setPeaDepuis]=useState(I("peaDepuis",""));const[perMontant,setPerMontant]=useState(I("perMontant",""));const[avMontant,setAvMontant]=useState(I("avMontant",""));
const[aCrypto,setACrypto]=useState(I("aCrypto",""));const[cryptoMontant,setCryptoMontant]=useState(I("cryptoMontant",""));const[immoValeur,setImmoValeur]=useState(I("immoValeur",""));const[autresActifs,setAutresActifs]=useState(I("autresActifs",""));
const[toleranceRisque,setToleranceRisque]=useState(I("toleranceRisque",""));const[horizon,setHorizon]=useState(I("horizon",""));const[reaction,setReaction]=useState(I("reaction",""));
const[userGoals,setUserGoals]=useState(I("userGoals",[]));const[entries,setEntries]=useState(I("entries",[]));const[actionsDone,setActionsDone]=useState(I("actionsDone",{}));const[soldeCourant,setSoldeCourant]=useState(I("soldeCourant",""));
const[positions,setPositions]=useState(I("positions",[]));const[showPF,setShowPF]=useState(false);const[newP,setNewP]=useState({nom:"",type:"ETF",enveloppe:"PEA",qte:"",pru:"",prix:""});
const[bpSalG,setBpSalG]=useState(I("bpSalG","2"));const[bpInfl,setBpInfl]=useState(I("bpInfl","2"));const[bpRetAct,setBpRetAct]=useState(I("bpRetAct","7"));const[bpRetAV,setBpRetAV]=useState(I("bpRetAV","4"));const[bpRetLiv,setBpRetLiv]=useState(I("bpRetLiv","2.4"));
const[bpEvents,setBpEvents]=useState(I("bpEvents",[]));const[showEF,setShowEF]=useState(false);const[newE,setNewE]=useState({date:new Date().toISOString().slice(0,7),pea:"",av:"",per:"",livrets:"",crypto:"",soldeCc:"",immo:"",autres:"",versement:"",retrait:"",notes:""});const[showEvF,setShowEvF]=useState(false);const[newEv,setNewEv]=useState({nom:"",annee:"",cout:""});const[showDCA,setShowDCA]=useState(false);
const[credits,setCredits]=useState(I("credits",[]));const[showCF,setShowCF]=useState(false);const[newCr,setNewCr]=useState({nom:"",restant:"",taux:"",mensualite:""});
const[bienPrix,setBienPrix]=useState("");const[apport,setApport]=useState("");const[tauxCr,setTauxCr]=useState("3.5");const[dureeCr,setDureeCr]=useState("25");const[loyerAct,setLoyerAct]=useState("");const[chargesCo,setChargesCo]=useState("");const[taxeF,setTaxeF]=useState("");

useEffect(()=>{saveState({page,step,done,age,statut,situationFam,nbEnfants,logement,pays,villeType,modeCouple,p2Rev,p2Ch,p2Ep,typeRevenu,brutAnnuel,netMensuel,primes,autresRev,loyer,alimentation,transports,abonnements,assurancesCh,loisirs,creditsConso,autresCharges,epargnePrecaution,montantEpargne,aLivretA,aLDDS,aPEA,aPER,aAV,peaMontant,peaDepuis,perMontant,avMontant,aCrypto,cryptoMontant,immoValeur,autresActifs,toleranceRisque,horizon,reaction,userGoals,entries,actionsDone,soldeCourant,positions,bpSalG,bpInfl,bpRetAct,bpRetAV,bpRetLiv,bpEvents,credits});});

const C=CO[pays]||CO.france;const cur=C.cur;const fc=n=>fmt(n)+" "+cur;
const getNet=()=>{if(typeRevenu==="net_mensuel")return(parseFloat(netMensuel)||0)+(parseFloat(primes)||0)/12+(parseFloat(autresRev)||0);const b=parseFloat(brutAnnuel)||0;const t=statut==="fonctionnaire"?0.83:statut==="independant"?0.55:0.75;return b*t/12+(parseFloat(primes)||0)/12+(parseFloat(autresRev)||0);};
const totalCh=()=>[loyer,alimentation,transports,abonnements,assurancesCh,loisirs,creditsConso,autresCharges].reduce((s,v)=>s+(parseFloat(v)||0),0);
const rev=getNet();const ch=totalCh();const dispo=rev-ch;
const coupleRev=modeCouple?rev+(parseFloat(p2Rev)||0):rev;const coupleCh=modeCouple?ch+(parseFloat(p2Ch)||0):ch;const coupleDispo=coupleRev-coupleCh;
const epNum=parseFloat(montantEpargne)||0;const moisEp=ch>0?epNum/ch:0;
